```bash
# Tableaux associatifs en awk
echo -e "chat\nchien\nchat\noiseau\nchien\nchien" | awk '
{
    count[$0]++
}
END {
    for (animal in count) {
        print animal, count[animal]
    }
}'
# chat 2
# chien 3
# oiseau 1

# Grouper et sommer
echo -e "alice 100\nbob 200\nalice 150\nbob 50" | awk '
{ total[$1] += $2 }
END {
    for (name in total) print name, total[name]
}'
# alice 250
# bob 250

# Conditions dans awk
echo -e "10\n25\n5\n30\n15" | awk '
NR==1 { max=min=$1 }
{ if ($1 > max) max=$1; if ($1 < min) min=$1 }
END { print "Min:", min, "Max:", max }'
# Min: 5 Max: 30
```
